+import React from "react";
+import useStyle from './styles.js';
+import { Card, CardActions, CardContent, CardMedia, Button, Typography } from '@material-ui/core';
+import ThumbUpAltIcon from '@material-ui/icons/ThumbUpAlt';
+import DeleteIcon from '@material-ui/icons/Delete';
+import MoreHorizIcon from '@material-ui/icons/MoreHoriz';
+import moment from 'moment';
+import { useDispatch } from 'react-redux';
+import { deletePost, likePost } from "../../../actions/posts.js";
+
+const Post = ({ post, setCurrentId }) => {
+    const classes = useStyle();
+    const dispatch = useDispatch();
+    const user = JSON.parse(localStorage.getItem('profile'));
+    const Likes = () => {
+        if (post.likeCount > 0) {
+            return post.like.find((like) => like === (user?.result?.googleId || user?.result?._id))
+            ? (<><ThumbUpAltIcon fontSize="small" />&nbsp;{post.likeCount > 2 ? `You and ${post.likeCount - 1} others` : `${post.likeCount} like${post.likeCount > 1 ? 's' : ''}` }</>)
+            : (<><ThumbUpAltIcon fontSize="small" />&nbsp;{post.likeCount} {post.likeCount === 1 ? 'Like' : 'Likes'}</>);
+        }
+        return <><ThumbUpAltIcon fontSize="small" />&nbsp;Like</>;
+    };
+
+    return (
+        <Card className={classes.card}>
+            <CardMedia className={classes.media} image={post.selectedFile} title={post.title} />
+            <div className={classes.overlay}>
+                <Typography variant="h6">{post.name}</Typography>
+                <Typography variant="body2">{moment(post.createdAt).fromNow()}</Typography>
+            </div>
+            <div className={classes.overlay2}>
+                <Button style={{ color: 'white' }} size="small" onClick={() => setCurrentId(post._id)}>
+                    <MoreHorizIcon fontSize="medium" />
+                </Button>
+            </div>
+            <div className={classes.details}>
+                <Typography variant="body2" color="textSecondary">
+                    {post.tags.map((tag) => `#${tag} `)}
+                </Typography>
+            </div>
+                <Typography className={classes.title} variant="h5" gutterBottom>{post.title}</Typography>
+            <CardContent>
+                <Typography variant="body2" color="textSecondary" component="p" gutterBottom>{post.message}</Typography>
+            </CardContent>
+            <CardActions className={classes.cardActions}>
+                <Button size="small" color="primary" disabled={!user.result} onClick={() => dispatch((likePost(post._id)))}>
+                    <ThumbUpAltIcon fontSize="small" />
+                    <Likes />
+                </Button>
+                <Button size="small" color="primary" onClick={() => dispatch(deletePost(post._id))}>
+                    <DeleteIcon fontSize="small" />
+                    Delete
+                </Button>
+            </CardActions>
+        </Card>
+    );
+}
+
+export default Post;
